17	export function isJSONSerializable(value: any): boolean {
18	  if (value === undefined) {
19	    return false;
20	  }
21	  const t = typeof value;
22	  if (t === "string" || t === "number" || t === "boolean" || t === null) {
23	    return true;
24	  }
25	  if (t !== "object") {
26	    return false; // bigint, function, symbol, undefined
27	  }
28	  if (Array.isArray(value)) {
29	    return true;
30	  }
31	  if (value.buffer) {
32	    return false;
33	  }
34	  // `FormData` and `URLSearchParams` should't have a `toJSON` method,
35	  // but Bun adds it, which is non-standard.
36	  if (value instanceof FormData || value instanceof URLSearchParams) {
37	    return false;
38	  }
39	  return (
40	    (value.constructor && value.constructor.name === "Object") ||
41	    typeof value.toJSON === "function"
42	  );
43	}
