54	// This provides reasonable defaults for the correct parser based on Content-Type header.
55	export function detectResponseType(_contentType = ""): ResponseType {
56	  if (!_contentType) {
57	    return "json";
58	  }
59	
60	  // Value might look like: `application/json; charset=utf-8`
61	  const contentType = _contentType.split(";").shift() || "";
62	
63	  if (JSON_RE.test(contentType)) {
64	    return "json";
65	  }
66	
67	  // TODO
68	  // if (contentType === 'application/octet-stream') {
69	  //   return 'stream'
70	  // }
71	
72	  // SSE
73	  // https://developer.mozilla.org/en-US/docs/Web/API/Server-sent_events/Using_server-sent_events#sending_events_from_the_server
74	  if (contentType === "text/event-stream") {
75	    return "stream";
76	  }
77	
78	  if (textTypes.has(contentType) || contentType.startsWith("text/")) {
79	    return "text";
80	  }
81	
82	  return "blob";
83	}
