export type CircuitState = "closed" | "open" | "half-open";

export interface CircuitBreakerEntry {
  state: CircuitState;
  consecutiveFailures: number;
  openedAt: number;
  halfOpenActive: number;
}

export interface ResolvedCircuitBreakerOptions {
  threshold: number;
  cooldown: number;
  halfOpenMaxRequests: number;
  failureStatusCodes: Set<number>;
}

export type CircuitBreakerRegistry = Map<string, CircuitBreakerEntry>;

const DEFAULT_FAILURE_STATUS_CODES = [408, 409, 425, 429, 500, 502, 503, 504];

export function resolveCircuitBreakerOptions(
  option: boolean | CircuitBreakerOptions | undefined
): ResolvedCircuitBreakerOptions | undefined {
  if (!option) {
    return undefined;
  }
  const opts = option === true ? {} : option;
  return {
    threshold: opts.threshold ?? 5,
    cooldown: opts.cooldown ?? 30_000,
    halfOpenMaxRequests: opts.halfOpenMaxRequests ?? 1,
    failureStatusCodes: new Set(
      opts.failureStatusCodes ?? DEFAULT_FAILURE_STATUS_CODES
    ),
  };
}

export function getCircuitOrigin(request: FetchRequest): string {
  try {
    if (typeof request === "string") {
      return new URL(request).origin;
    }
    if (request instanceof URL) {
      return request.origin;
    }
    if (typeof Request !== "undefined" && request instanceof Request) {
      return new URL(request.url).origin;
    }
  } catch {
    // Fall through to a best-effort key below.
  }
  return typeof request === "string"
    ? request
    : String((request as { url?: string })?.url ?? request);
}

export function getCircuitEntry(
  registry: CircuitBreakerRegistry,
  origin: string
): CircuitBreakerEntry {
  let entry = registry.get(origin);
  if (!entry) {
    entry = {
      state: "closed",
      consecutiveFailures: 0,
      openedAt: 0,
      halfOpenActive: 0,
    };
    registry.set(origin, entry);
  }
  return entry;
}

export interface CircuitGateResult {
  allowed: boolean;
  probe: boolean;
}

export function acquireCircuitSlot(
  entry: CircuitBreakerEntry,
  config: ResolvedCircuitBreakerOptions,
  now: number
): CircuitGateResult {
  if (entry.state === "open") {
    if (now - entry.openedAt >= config.cooldown) {
      entry.state = "half-open";
      entry.halfOpenActive = 0;
    } else {
      return { allowed: false, probe: false };
    }
  }

  if (entry.state === "half-open") {
    if (entry.halfOpenActive >= config.halfOpenMaxRequests) {
      return { allowed: false, probe: false };
    }
    entry.halfOpenActive++;
    return { allowed: true, probe: true };
  }

  return { allowed: true, probe: false };
}

export type CircuitOutcome = "success" | "failure" | "neutral";

export function classifyCircuitError(
  error: unknown,
  config: ResolvedCircuitBreakerOptions
): CircuitOutcome {
  const status = (error as { status?: number })?.status;
  if (typeof status === "number" && !config.failureStatusCodes.has(status)) {
    return "neutral";
  }
  return "failure";
}

export function classifyCircuitResponse(
  status: number,
  config: ResolvedCircuitBreakerOptions
): CircuitOutcome {
  return config.failureStatusCodes.has(status) ? "failure" : "success";
}

export function recordCircuitOutcome(
  entry: CircuitBreakerEntry,
  config: ResolvedCircuitBreakerOptions,
  outcome: CircuitOutcome,
  probe: boolean,
  now: number
): void {
  switch (outcome) {
    case "success": {
      entry.consecutiveFailures = 0;
      entry.state = "closed";
      entry.openedAt = 0;
      break;
    }
    case "failure": {
      if (probe) {
        entry.state = "open";
        entry.openedAt = now;
      } else {
        entry.consecutiveFailures++;
        if (entry.consecutiveFailures >= config.threshold) {
          entry.state = "open";
          entry.openedAt = now;
        }
      }
      break;
    }
    case "neutral": {
      // Neither resets the failure streak nor closes half-open state.
      break;
    }
  }

  if (probe) {
    entry.halfOpenActive = Math.max(0, entry.halfOpenActive - 1);
  }
}
